firmware_template.source:
#include "dht22.h"
#include <DHT.h>
#define DHT_PIN 4
static DHT dht(DHT_PIN,DHT22);
static float _t=0,_h=0,_hi=0;
static unsigned long _last=0;
void dht22_setup(){dht.begin();Serial.println("[dht22] OK");}
void dht22_loop(){if(millis()-_last<2000)return;_last=millis();_t=dht.readTemperature();_h=dht.readHumidity();if(!isnan(_t)&&!isnan(_h))_hi=dht.computeHeatIndex(_t,_h,false);}
float dht22_get_temperature(){return _t;}
float dht22_get_humidity(){return _h;}
float dht22_get_heat_index(){return _hi;}
